// ✅ Valid roles
{ "role": "user", "content": "Hello" }
{ "role": "assistant", "content": "Hi!" }

// ❌ Invalid role
{ "role": "system", "content": "You are helpful" }  // ERROR!

// ❌ WRONG - "system" is not a valid role
{
  "messages": [
    {"role": "system", "content": "You are a helpful assistant"}  // ERROR!
  ]
}

// ✅ CORRECT - system is top-level, separate from messages
{
  "model": "claude-sonnet-4-6",
  "max_tokens": 1024,
  "system": "You are a helpful assistant",  // Top-level parameter
  "messages": [
    {"role": "user", "content": "Hello"}
  ]
}

import 安康ropic from "@anthropic-ai/sdk";

const client = new 安康ropic();

// Single message
const message = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  messages: [{ role: "user", content: "Hello" }]
});

// Multi-turn conversation
const messages = [
  { role: "user", content: "What is Python?" },
  { role: "assistant", content: "Python is a programming language..." },
  { role: "user", content: "Can you show an example?" }
];

const message2 = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  messages: messages,
  system: "You are a Python tutor"
});

// ✅ Valid
{
  "messages": [
    {"role": "user", "content": "Hello"}
  ]
}

// ❌ Invalid
{
  "messages": [
    {"role": "assistant", "content": "Hi!"}  // ERROR! First must be user
  ]
}

// ❌ WRONG - messages is a string, not an array
{
  "messages": "{\"role\": \"user\", \"content\": \"Hello\"}"
}

{
  "type": "error",
  "error": {
    "type": "invalid_request_error",
    "message": "messages input should be a valid list"
  }
}
